  kind: "config-patch";
  skill: string;
  agent: AgentId;
  target: string;
}

export interface TomlPatchRevertAction {
  kind: "toml-patch";
  skill: string;
  agent: AgentId;
  target: string;
}

export interface FrontmatterEmitRevertAction {
  kind: "frontmatter-emit";
  skill: string;
  agent: AgentId;
  target: string;
}

