  | "create-symlink"
  | "copy-dir"
  | "write-file"
  | "patch-config"
  | "patch-toml"
  | "emit-frontmatter"
  | "remove"
  | "unapply-patch";

export interface PlannedChange {
  verb: PlannedChangeVerb;
  kind:
    | "skill-dir"
    | "file-write"
    | "config-patch"
    | "toml-patch"
