  | ConfigPatchRevertAction
  | TomlPatchRevertAction
  | FrontmatterEmitRevertAction;

export type PlannedChangeVerb =
  | "create-symlink"
  | "copy-dir"
  | "write-file"
  | "patch-config"
  | "patch-toml"
  | "emit-frontmatter"
  | "remove"
  | "unapply-patch";

export interface PlannedChange {
